import{_ as a,o as t,c as o,a2 as i}from"./chunks/framework.Crpw6aS5.js";const c=JSON.parse('{"title":"1981年巴菲特致股东的信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1981年/核心总结.md","filePath":"01_letters/1981年/核心总结.md"}'),e={name:"01_letters/1981年/核心总结.md"};function r(n,l,s,u,h,d){return t(),o("div",null,[...l[0]||(l[0]=[i('<h1 id="_1981年巴菲特致股东的信核心总结" tabindex="-1">1981年巴菲特致股东的信核心总结 <a class="header-anchor" href="#_1981年巴菲特致股东的信核心总结" aria-label="Permalink to &quot;1981年巴菲特致股东的信核心总结&quot;">​</a></h1><h2 id="简要导读" tabindex="-1">简要导读 <a class="header-anchor" href="#简要导读" aria-label="Permalink to &quot;简要导读&quot;">​</a></h2><p>1981年这封信，巴菲特把他的收购哲学讲得淋漓尽致，一针见血点破很多企业收购的通病，把我们带到巴菲特内心深处看待企业收购底层逻辑。同时，他也在高利率背景下，第一次清晰推导出：高通胀+高利率下，平均股权其实对个人投资者没有&quot;增值&quot;，甚至是负贡献，这个推理至今震撼。文末可下载英文原版PDF。</p><h2 id="一、巴菲特的收购哲学-为什么我们宁愿买十分之一-也不买整个" tabindex="-1">一、巴菲特的收购哲学：为什么我们宁愿买十分之一，也不买整个 <a class="header-anchor" href="#一、巴菲特的收购哲学-为什么我们宁愿买十分之一-也不买整个" aria-label="Permalink to &quot;一、巴菲特的收购哲学：为什么我们宁愿买十分之一，也不买整个&quot;">​</a></h2><ul><li><p>核心观点：<strong>我们宁愿以X价格买优秀公司10%股权，也不愿以2X价格买整个100%</strong>，大多数管理层正好反过来。为什么大多数管理层反过来？巴菲特说三个原因：</p><ol><li><strong>动物精神</strong>：管理层就喜欢更大规模更多活动，越做越大才有成就感</li><li><strong>考核机制</strong>：整个世界都是按规模考核、给薪酬，没人按ROE和股东增值考核</li><li><strong>王子童话幻觉</strong>：很多管理层相信自己的管理之吻能把癞蛤蟆变成王子，很多收购本来就是烂生意，管理层以为自己能救，结果绝大多数吻都没用，&quot;我们看过很多吻，很少奇迹&quot;。</li></ol></li><li><p>真正能做好收购的两类公司：</p><ol><li>天生就买适应通胀的好生意——要同时满足两个条件：轻松涨价不怕丢份额，不需要太多新增资本就能容纳名义增长——这种企业太少，抢得太凶，已经太贵了。</li><li>管理层巨星，真能认出伪装成癞蛤蟆的王子，有能力剥掉伪装——这类人太少了，汤姆·墨菲（首都城市）是典范，而且这类大师通常很少做交易，更喜欢回购自家股票。</li></ol></li><li><p>巴菲特自己：&quot;我不属于第二类，对第一类理解得不错，但做得不好，讲道比行道好&quot;，最成功的还是低价买优秀公司的少数股权。</p></li></ul><h2 id="二、残酷现实-高利率下-平均股权其实没创造价值" tabindex="-1">二、残酷现实：高利率下，平均股权其实没创造价值 <a class="header-anchor" href="#二、残酷现实-高利率下-平均股权其实没创造价值" aria-label="Permalink to &quot;二、残酷现实：高利率下，平均股权其实没创造价值&quot;">​</a></h2><ul><li><p>几十年前：长期债券收益才3-5%，企业ROE 10%，就比被动投资高，所以股票能增值，市场愿意给溢价。现在呢？</p><ul><li>1981年长期免税债券收益率已经14%，企业平均ROE才14%，但是个人拿到手还要交税，税后肯定比债券被动收益低！</li><li>比如50%税率档，全分红的话，14%ROE给你的税后收益相当于7%免税债券，当时7%免税债券市场只值50块钱面值。哪怕全留存，盈利增长14%，卖掉还要交20%资本利得税，净回报还是不如当前被动投资。</li><li>结论：<strong>现在美国股权整体对个人投资者没有增值，就是因为被动收益率（债券）涨得比企业ROE快多了</strong>，除非通胀下来，债券收益率跌下去，否则这个情况难改变。</li></ul></li><li><p>更讽刺的是：通胀这个绦虫，低回报企业不得不留存更多盈利，明明应该高分红让股东去投更好的地方，结果通胀逼着它们把所有钱都留在企业，就为了维持原有规模，好钱投坏钱，股东吃亏。这个逻辑太深刻了。</p></li></ul><h2 id="三、非控股收益已经比我们自己赚得多" tabindex="-1">三、非控股收益已经比我们自己赚得多 <a class="header-anchor" href="#三、非控股收益已经比我们自己赚得多" aria-label="Permalink to &quot;三、非控股收益已经比我们自己赚得多&quot;">​</a></h2><ul><li><p>现在我们不控制的优秀公司，未分配利润加起来已经超过我们自己报表营业收益，四大重仓：GEICO、通用食品、雷诺兹、华盛顿邮报，一年未分配利润就超过3500万美元，这些都没体现在我们报表里，但不代表它们不存在，&quot;树长在我们部分拥有的森林，我们就拥有那部分树&quot;。</p></li><li><p>整体来说，我们买的这些非控股企业，基本面比我们自己控制的更好，因为二级市场能低价买到好公司部分股权，整家买好公司太贵了。</p></li></ul><h2 id="四、保险行业-未来十年承保会更差" tabindex="-1">四、保险行业：未来十年承保会更差 <a class="header-anchor" href="#四、保险行业-未来十年承保会更差" aria-label="Permalink to &quot;四、保险行业：未来十年承保会更差&quot;">​</a></h2><ul><li><p>当前定价已经错得离谱，保费增长只有3.6%，远低于要稳住亏损需要的10%，综合成本率已经105.7%，巴菲特预言：&quot;1982一定是近年最差，未来十年，最好的年份看起来也比过去平均差&quot;。为什么？</p><ul><li><p>很多保险公司之前买了大量长期债券，现在债券价格大跌，会计上还按摊余成本持有，不敢认赔，所以为了维持现金流，只能低价抢业务，哪怕亏钱也要卖，全行业都被拖下水。巴菲特说，几乎没人愿意主动缩量，让现金流变负，所以价格上不去。我们自己能做的就是坚持纪律，牺牲规模，保持优质，等着看。</p></li><li><p>GEICO是例外，它效率太高，成本比别人低太多，所以位置安全得多，GEICO是天才商业想法，被天才运营。</p></li></ul></li></ul><h2 id="五、其他亮点-股东指定捐赠" tabindex="-1">五、其他亮点：股东指定捐赠 <a class="header-anchor" href="#五、其他亮点-股东指定捐赠" aria-label="Permalink to &quot;五、其他亮点：股东指定捐赠&quot;">​</a></h2><ul><li>巴菲特推出股东自己指定捐赠给谁，股东参与率95.6%，太受欢迎了。这是查理·芒格想出来的点子，真正把股东钱还给股东决定怎么花，反对&quot;老板最懂&quot;公司治理那套，巴菲特说，居然没有一个股东让管理层替他选，也没人要求匹配董事选的慈善，和很多大公司正好反过来。</li></ul><h2 id="六、核心启示" tabindex="-1">六、核心启示 <a class="header-anchor" href="#六、核心启示" aria-label="Permalink to &quot;六、核心启示&quot;">​</a></h2><ol><li><strong>收购的陷阱</strong>：绝大多数收购坏不是因为执行不好，是一开始买贵了，买了烂生意，管理层误以为自己能扭转，很多收购就是为了满足管理层做大的欲望，不是为了股东赚钱。</li><li><strong>水涨船高</strong>：无风险利率是所有资产定价的锚，利率涨了，哪怕企业盈利不变，估值也得降，这个道理什么时候都对。</li><li><strong>通胀是绦虫</strong>：通胀一点点吃掉企业资本，低ROE企业不得不把所有盈利再投进去，维持规模，股东什么都拿不到，这个隐形伤害很多人看不到。</li><li><strong>优秀的公司治理就是股东真当家</strong>：让股东自己决定钱捐给谁，小事见大智慧。</li></ol><hr><blockquote><p>📎 <strong>文末小惊喜</strong>：可点击下载<a href="Chairman&#39;s%20Letter%20-%201981.pdf">巴菲特1981年股东信原件PDF</a>，原汁原味阅读英文原文。</p></blockquote>',17)])])}const q=a(e,[["render",r]]);export{c as __pageData,q as default};
